import tiktoken
from anthropic import Anthropic

# ── OpenAI-compatible token counting ─────────────────────────────────────────
def count_tokens_openai(text: str, model: str = "gpt-4o-mini") -> int:
    """Count tokens using tiktoken (exact for OpenAI models)."""
    enc = tiktoken.encoding_for_model(model)
    return len(enc.encode(text))

def count_messages_openai(messages: list[dict], model: str = "gpt-4o-mini") -> int:
    """Approximate token count for a messages list, including overhead."""
    enc = tiktoken.encoding_for_model(model)
    total = 0
    for msg in messages:
        total += 4  # per-message overhead: role + separators
        for value in msg.values():
            total += len(enc.encode(str(value)))
    total += 2  # priming tokens for assistant reply
    return total

# ── Anthropic token counting (exact, uses the API) ───────────────────────────
client = Anthropic()

def count_tokens_claude(
    messages: list[dict],
    system: str = "",
    model: str = "claude-sonnet-4-20250514",
    tools: list[dict] | None = None,
) -> int:
    """Exact token count via Anthropic's count_tokens endpoint (no charge)."""
    kwargs = {"model": model, "messages": messages}
    if system:
        kwargs["system"] = system
    if tools:
        kwargs["tools"] = tools
    result = client.messages.count_tokens(**kwargs)
    return result.input_tokens

from dataclasses import dataclass

MODEL_LIMITS = {
    "gpt-4o-mini":            128_000,
    "gpt-4o":                 128_000,
    "claude-haiku-4-20250514": 200_000,
    "claude-sonnet-4-20250514": 200_000,
}

@dataclass
class ContextBudget:
    model: str
    system_tokens: int
    tool_tokens: int
    max_output_tokens: int
    safety_margin: float = 0.85  # never use more than 85% of window

    @property
    def window(self) -> int:
        return MODEL_LIMITS[self.model]

    @property
    def usable(self) -> int:
        return int(self.window * self.safety_margin)

    @property
    def fixed_overhead(self) -> int:
        return self.system_tokens + self.tool_tokens + self.max_output_tokens

    @property
    def available_for_history_and_rag(self) -> int:
        return max(0, self.usable - self.fixed_overhead)

    def utilization(self, history_tokens: int, rag_tokens: int) -> float:
        used = self.fixed_overhead + history_tokens + rag_tokens
        return used / self.window

    def fits(self, history_tokens: int, rag_tokens: int) -> bool:
        return self.utilization(history_tokens, rag_tokens) <= self.safety_margin


# Example
budget = ContextBudget(
    model="claude-sonnet-4-20250514",
    system_tokens=800,
    tool_tokens=3200,
    max_output_tokens=4096,
)
print(f"Window:           {budget.window:,} tokens")
print(f"Usable (85%):     {budget.usable:,} tokens")
print(f"Fixed overhead:   {budget.fixed_overhead:,} tokens")
print(f"For history+RAG:  {budget.available_for_history_and_rag:,} tokens")
# Window:           200,000 tokens
# Usable (85%):     170,000 tokens
# Fixed overhead:    8,096 tokens
# For history+RAG:  161,904 tokens
